const items = $input.all();
const distributors = items.map(item => ({
  id: item.json.id,
  razao_social: item.json.razao_social,
  cidade: item.json.cidade,
  estado: item.json.estado,
  telefone: item.json.telefone || null
}));

let message = '';
if (distributors.length > 0) {
  message = distributors.map((d, i) => {
    const fone = d.telefone ? `\n   Tel: ${d.telefone}` : '';
    return `${i+1}. *${d.razao_social}*\n   Cidade: ${d.cidade} - ${d.estado}${fone}`;
  }).join('\n\n');
} else {
  message = 'Nenhum distribuidor encontrado neste estado. Estamos expandindo nossa rede!';
}

return [{
  json: {
    distributors,
    count: distributors.length,
    message,
    found: distributors.length > 0
  }
}];
